using System.Collections.Generic;
using UnityEngine;

public partial class PlayerProgress : MonoBehaviour
{
    // ---------------- Progressão por Área ----------------

    public int GetDeaths(string areaId) => TryGetAreaProgress(areaId)?.deaths ?? 0;
    public int GetDeaths(AreaData area) => area != null ? GetDeaths(area.areaId) : 0;

    public void RegisterDeath(string areaId) => GetOrCreateAreaProgress(areaId).deaths++;
    public void RegisterDeath(AreaData area)
    {
        if (area != null) RegisterDeath(area.areaId);
    }

    public bool HasVisited(string areaId) => TryGetAreaProgress(areaId)?.visited ?? false;
    public bool HasVisited(AreaData area) => area != null && HasVisited(area.areaId);

    public void MarkVisited(string areaId) => GetOrCreateAreaProgress(areaId).visited = true;
    public void MarkVisited(AreaData area)
    {
        if (area != null) MarkVisited(area.areaId);
    }

    public bool IsFirstVisit(string areaId) => !HasVisited(areaId);
    public bool IsFirstVisit(AreaData area) => area != null && IsFirstVisit(area.areaId);

    /// <summary>True se a área já foi "aberta" (acesso desbloqueado — ex: porta/portão/ponte activados), distinto de "visitada" (jogador já lá esteve).</summary>
    public bool IsOpened(string areaId) => TryGetAreaProgress(areaId)?.opened ?? false;
    public bool IsOpened(AreaData area) => area != null && IsOpened(area.areaId);

    public void MarkOpened(string areaId) => GetOrCreateAreaProgress(areaId).opened = true;
    public void MarkOpened(AreaData area)
    {
        if (area != null) MarkOpened(area.areaId);
    }

    // ---------------- Descobertas da Área (Menu de Pausa: Área Atual) ----------------

    public int GetRunasFound(string areaId) => TryGetAreaProgress(areaId)?.runasFound ?? 0;
    public int GetRunasFound(AreaData area) => area != null ? GetRunasFound(area.areaId) : 0;

    /// <summary>Regista mais uma Runa de Gaia encontrada nesta área (limitado a AreaData.totalRunas, se fornecida).</summary>
    public void AddRunaFound(AreaData area)
    {
        if (area == null) return;
        var ap = GetOrCreateAreaProgress(area.areaId);
        ap.runasFound = area.totalRunas > 0 ? Mathf.Min(ap.runasFound + 1, area.totalRunas) : ap.runasFound + 1;
    }

    public int GetNpcsRescued(string areaId) => TryGetAreaProgress(areaId)?.npcsRescued ?? 0;
    public int GetNpcsRescued(AreaData area) => area != null ? GetNpcsRescued(area.areaId) : 0;

    /// <summary>True se o NPC com este "npcId" já foi resgatado nesta área.</summary>
    public bool IsNpcRescued(AreaData area, string npcId)
    {
        if (area == null || string.IsNullOrEmpty(npcId)) return false;
        return TryGetAreaProgress(area.areaId)?.rescuedNpcIds.Contains(npcId) ?? false;
    }

    /// <summary>
    /// Regista um NPC como resgatado nesta área. Se "npcId" for fornecido, a
    /// operação é idempotente — chamadas repetidas com o mesmo ID não duplicam a
    /// contagem nem disparam eventos novamente. Se "npcId" for vazio/nulo, o
    /// comportamento antigo é mantido (incrementa sem verificar duplicados).
    ///
    /// Quando "npcId" é fornecido:
    ///   • Adiciona o ID a <see cref="AreaProgress.rescuedNpcIds"/>.
    ///   • Incrementa <see cref="AreaProgress.npcsRescued"/> (limitado ao total da área).
    ///   • Define automaticamente a variável global "NpcResgatado_&lt;npcId&gt;" = true em
    ///     <see cref="GameVariables"/> — permite usar Condition_BoolVariable para
    ///     verificar o resgate sem configurar Action_SetBoolVariable manualmente.
    ///   • Sincroniza a população da vila correspondente em WorldState.
    /// </summary>
    public void AddNpcRescued(AreaData area, string npcId)
    {
        if (area == null) return;

        // Task #21: npcId é obrigatório para garantir idempotência. Sem ID não há
        // como saber se este NPC já foi contado, abrindo a porta a duplicação de
        // população sempre que o evento volta a correr (recarregar cena, etc.).
        if (string.IsNullOrEmpty(npcId))
        {
            Debug.LogError($"[PlayerProgress] AddNpcRescued chamado sem npcId para a área \"{area.areaId}\". Preenche o campo npcId em Action_RescueNpc para garantir idempotência.");
            return;
        }

        var ap = GetOrCreateAreaProgress(area.areaId);

        // Idempotência: se o npcId já está na lista, não fazer nada.
        if (ap.rescuedNpcIds.Contains(npcId))
            return;

        ap.rescuedNpcIds.Add(npcId);

        // Variável automática: permite Condition_BoolVariable sem configuração extra.
        GameVariables.Instance?.SetBool($"NpcResgatado_{npcId}", true);

        ap.npcsRescued = area.totalNpcsToRescue > 0
            ? Mathf.Min(ap.npcsRescued + 1, area.totalNpcsToRescue)
            : ap.npcsRescued + 1;

        // Auto-sync: actualiza WorldState.villagePopulations para que o HUD e
        // outros sistemas (música, lojas, decoração) reflictam o resgate imediatamente.
        SyncVillagePopulationForWorld(area.world);
    }

    /// <summary>
    /// Re-calcula e sincroniza a população de uma vila específica (world.mainVillageId)
    /// somando todos os npcsRescued e totalNpcsToRescue das áreas desse mundo.
    /// Chamado automaticamente por AddNpcRescued e pode ser chamado externamente.
    /// </summary>
    public void SyncVillagePopulationForWorld(WorldData world)
    {
        if (world == null || string.IsNullOrEmpty(world.mainVillageId)) return;
        var db = GameDatabase.Instance;
        var ws = WorldState.Instance;
        if (db == null || ws == null) return;

        int totalRescued = 0, totalMax = 0;
        foreach (var a in db.areas)
        {
            if (a == null || a.world != world) continue;
            totalRescued += GetNpcsRescued(a);
            totalMax += a.totalNpcsToRescue;
        }
        ws.SyncRescuedPopulation(world.mainVillageId, totalRescued, totalMax);
    }

    /// <summary>
    /// Re-calcula e sincroniza a população de TODAS as vilas a partir dos resgates
    /// registados. Chamado por WorldState.RestoreFrom após carregar um save, para
    /// garantir consistência mesmo em saves criados antes desta sincronização ser
    /// implementada.
    /// </summary>
    public void SyncAllVillagePopulations()
    {
        var db = GameDatabase.Instance;
        if (db == null) return;

        // Agrupa áreas por mundo e soma os contadores.
        var totals = new System.Collections.Generic.Dictionary<string, (int rescued, int max)>();
        foreach (var area in db.areas)
        {
            if (area == null || area.world == null) continue;
            string vid = area.world.mainVillageId;
            if (string.IsNullOrEmpty(vid)) continue;
            if (!totals.ContainsKey(vid)) totals[vid] = (0, 0);
            var t = totals[vid];
            totals[vid] = (t.rescued + GetNpcsRescued(area), t.max + area.totalNpcsToRescue);
        }

        var ws = WorldState.Instance;
        if (ws == null) return;
        foreach (var kv in totals)
            ws.SyncRescuedPopulation(kv.Key, kv.Value.rescued, kv.Value.max);
    }

    public int GetWhispersFound(string areaId) => TryGetAreaProgress(areaId)?.whispersFound ?? 0;
    public int GetWhispersFound(AreaData area) => area != null ? GetWhispersFound(area.areaId) : 0;

    /// <summary>Regista mais um Sussurro da Terra encontrado nesta área (limitado a AreaData.totalWhispers, se fornecida) e actualiza o contador global.</summary>
    public void AddWhisperFound(AreaData area)
    {
        if (area == null) return;
        var ap = GetOrCreateAreaProgress(area.areaId);
        int before = ap.whispersFound;
        ap.whispersFound = area.totalWhispers > 0 ? Mathf.Min(ap.whispersFound + 1, area.totalWhispers) : ap.whispersFound + 1;
        if (ap.whispersFound > before) totalSussurrosCollected++;
    }

    public int GetWhispersDelivered(string areaId) => TryGetAreaProgress(areaId)?.whispersDelivered ?? 0;
    public int GetWhispersDelivered(AreaData area) => area != null ? GetWhispersDelivered(area.areaId) : 0;

    /// <summary>Regista a entrega de mais um Sussurro da Terra nesta área (limitado a AreaData.totalWhispers, se fornecida) — distinto de "encontrado" (ver AddWhisperFound).</summary>
    public void AddWhisperDelivered(AreaData area)
    {
        if (area == null) return;
        var ap = GetOrCreateAreaProgress(area.areaId);
        ap.whispersDelivered = area.totalWhispers > 0 ? Mathf.Min(ap.whispersDelivered + 1, area.totalWhispers) : ap.whispersDelivered + 1;
    }

    public int GetChestsFound(string areaId) => TryGetAreaProgress(areaId)?.chestsFound ?? 0;
    public int GetChestsFound(AreaData area) => area != null ? GetChestsFound(area.areaId) : 0;

    /// <summary>Regista mais um baú aberto nesta área (limitado a AreaData.totalChests, se fornecida) e actualiza o contador global.</summary>
    public void AddChestFound(AreaData area)
    {
        if (area == null) return;
        var ap = GetOrCreateAreaProgress(area.areaId);
        int before = ap.chestsFound;
        ap.chestsFound = area.totalChests > 0 ? Mathf.Min(ap.chestsFound + 1, area.totalChests) : ap.chestsFound + 1;
        if (ap.chestsFound > before) totalChestsOpenedGlobal++;
    }

    public int GetFragmentsFound(string areaId) => TryGetAreaProgress(areaId)?.fragmentsFound ?? 0;
    public int GetFragmentsFound(AreaData area) => area != null ? GetFragmentsFound(area.areaId) : 0;

    /// <summary>Regista mais um Fragmento Vital encontrado nesta área (limitado a AreaData.totalFragments, se fornecida).</summary>
    public void AddFragmentFound(AreaData area)
    {
        if (area == null) return;
        var ap = GetOrCreateAreaProgress(area.areaId);
        ap.fragmentsFound = area.totalFragments > 0 ? Mathf.Min(ap.fragmentsFound + 1, area.totalFragments) : ap.fragmentsFound + 1;
    }

    // ---------------- Ecos Perdidos (por área) ----------------

    public int GetEcosPerdidosFound(string areaId) => TryGetAreaProgress(areaId)?.ecosPerdidosFound ?? 0;
    public int GetEcosPerdidosFound(AreaData area) => area != null ? GetEcosPerdidosFound(area.areaId) : 0;

    /// <summary>
    /// Regista mais um Eco Perdido encontrado nesta área (limitado a
    /// AreaData.totalEcosPerdidos, se fornecida) e dá +1 ao saldo global de
    /// Ecos Perdidos do jogador (GiveEcosPerdidos, que actualiza o evento).
    /// </summary>
    public void AddEcoPerdidoFound(AreaData area)
    {
        if (area == null) return;
        var ap = GetOrCreateAreaProgress(area.areaId);
        int before = ap.ecosPerdidosFound;
        ap.ecosPerdidosFound = area.totalEcosPerdidos > 0
            ? Mathf.Min(ap.ecosPerdidosFound + 1, area.totalEcosPerdidos)
            : ap.ecosPerdidosFound + 1;

        if (ap.ecosPerdidosFound > before)
            GiveEcosPerdidos(1);
    }

    // ---------------- Melodias Selvagens ----------------

    /// <summary>True se a melodia com este "melodyId" já foi colectada.</summary>
    public bool HasCollectedMelody(string melodyId) =>
        !string.IsNullOrEmpty(melodyId) && _collectedMelodyIds.Contains(melodyId);

    /// <summary>
    /// Regista a melodia "melodyId" como colectada e incrementa o contador da
    /// área "area" (se fornecida). Idempotente — não duplica.
    /// Dispara <see cref="PickupCollected"/> (PickupType.WildMelody) para que
    /// sistemas externos (EmblemManager, UI, etc.) possam reagir.
    /// </summary>
    public void MarkMelodyCollected(string melodyId, AreaData area)
    {
        if (string.IsNullOrEmpty(melodyId)) return;
        if (_collectedMelodyIds.Contains(melodyId)) return;

        _collectedMelodyIds.Add(melodyId);

        if (area != null)
        {
            var ap = GetOrCreateAreaProgress(area.areaId);
            ap.melodiesFound = area.totalMelodies > 0
                ? Mathf.Min(ap.melodiesFound + 1, area.totalMelodies)
                : ap.melodiesFound + 1;
        }

        // Notifica o EmblemManager e outros sistemas.
        PickupCollected?.Invoke(PickupType.WildMelody, melodyId);

        // Verifica se o desbloqueio de uma melodia completa o 100% da área
        // ou do jogo → dispara CheckAll do EmblemManager.
        EmblemManager.Instance?.CheckAll();
    }

    /// <summary>Melodias Selvagens encontradas nesta área.</summary>
    public int GetMelodiesFound(string areaId) => TryGetAreaProgress(areaId)?.melodiesFound ?? 0;
    public int GetMelodiesFound(AreaData area) => area != null ? GetMelodiesFound(area.areaId) : 0;

    /// <summary>O jogador já encontrou/descobriu o desafio opcional desta área (mostra "?" até aqui).</summary>
    public bool IsChallengeDiscovered(string areaId) => TryGetAreaProgress(areaId)?.challengeDiscovered ?? false;
    public bool IsChallengeDiscovered(AreaData area) => area != null && IsChallengeDiscovered(area.areaId);

    public void MarkChallengeDiscovered(AreaData area)
    {
        if (area != null) GetOrCreateAreaProgress(area.areaId).challengeDiscovered = true;
    }

    public bool IsChallengeCompleted(string areaId) => TryGetAreaProgress(areaId)?.challengeCompleted ?? false;
    public bool IsChallengeCompleted(AreaData area) => area != null && IsChallengeCompleted(area.areaId);

    public void MarkChallengeCompleted(AreaData area)
    {
        if (area == null) return;
        var ap = GetOrCreateAreaProgress(area.areaId);
        ap.challengeCompleted = true;
        ap.challengeDiscovered = true;
    }

    /// <summary>Sussurros da Terra (frases exactas ditas por NPCs) já ouvidos sobre esta área — usado em "SUSSURROS DA TERRA" no Menu de Pausa.</summary>
    public IReadOnlyList<string> GetSussurrosDaTerraOuvidos(string areaId) => TryGetAreaProgress(areaId)?.sussurrosDaTerraOuvidos ?? (IReadOnlyList<string>)System.Array.Empty<string>();
    public IReadOnlyList<string> GetSussurrosDaTerraOuvidos(AreaData area) => area != null ? GetSussurrosDaTerraOuvidos(area.areaId) : null;

    /// <summary>
    /// Regista um Sussurro da Terra (frase exacta dita por um NPC) sobre esta área, se ainda não
    /// tiver sido ouvido. É a mesma colecionável da contagem "Sussurros da Terra" das Descobertas
    /// da área — por isso também conta como um Sussurro da Terra encontrado (ver AddWhisperFound).
    /// </summary>
    public void AddSussurroDaTerra(AreaData area, string phrase)
    {
        if (area == null || string.IsNullOrEmpty(phrase)) return;
        var ap = GetOrCreateAreaProgress(area.areaId);
        if (ap.sussurrosDaTerraOuvidos.Contains(phrase)) return;

        ap.sussurrosDaTerraOuvidos.Add(phrase);
        AddWhisperFound(area);
    }

    /// <summary>
    /// Percentagem de conclusão de uma área (0–100), considerando apenas
    /// conteúdo permanente. Critérios que entram no cálculo:
    ///   • Runas de Gaia
    ///   • NPCs resgatados
    ///   • Sussurros da Terra encontrados (whispersFound — a entrega é contada
    ///     no total global, não nesta vista por área)
    ///   • Baús abertos
    ///   • Fragmentos Vitais recolhidos
    ///   • Animal libertado (area.freedAnimalForm)
    ///   • Desafio opcional concluído (area.hasOptionalChallenge)
    ///   • Melodias Selvagens recolhidas (area.totalMelodies)
    ///
    /// Excluídos: Sementes, Ecos Perdidos, inimigos.
    /// </summary>
    public int GetAreaCompletionPercent(AreaData area)
    {
        if (area == null) return 0;

        var ap = GetOrCreateAreaProgress(area.areaId);

        int total = 0;
        int found = 0;

        if (area.totalRunas > 0) { total += area.totalRunas; found += Mathf.Min(ap.runasFound, area.totalRunas); }
        if (area.totalNpcsToRescue > 0) { total += area.totalNpcsToRescue; found += Mathf.Min(ap.npcsRescued, area.totalNpcsToRescue); }
        if (area.totalWhispers > 0) { total += area.totalWhispers; found += Mathf.Min(ap.whispersFound, area.totalWhispers); }
        if (area.totalChests > 0) { total += area.totalChests; found += Mathf.Min(ap.chestsFound, area.totalChests); }
        if (area.totalFragments > 0) { total += area.totalFragments; found += Mathf.Min(ap.fragmentsFound, area.totalFragments); }

        if (area.freedAnimalForm != null)
        {
            total += 1;
            if (_freedAnimalIds.Contains(area.freedAnimalForm.formId)) found += 1;
        }

        if (area.hasOptionalChallenge)
        {
            total += 1;
            if (ap.challengeCompleted) found += 1;
        }

        if (area.totalMelodies > 0) { total += area.totalMelodies; found += Mathf.Min(ap.melodiesFound, area.totalMelodies); }

        if (total <= 0) return 0;
        return Mathf.RoundToInt(100f * found / total);
    }

    private AreaProgress GetOrCreateAreaProgress(string areaId)
    {
        for (int i = 0; i < areaProgress.Count; i++)
            if (areaProgress[i].areaId == areaId) return areaProgress[i];

        var created = new AreaProgress { areaId = areaId };
        areaProgress.Add(created);
        return created;
    }

    /// <summary>
    /// Versão read-only: devolve o AreaProgress existente ou null.
    /// Usar nos getters de leitura para não criar entradas vazias no save
    /// quando a área ainda não foi visitada (Task #20).
    /// </summary>
    private AreaProgress TryGetAreaProgress(string areaId)
    {
        for (int i = 0; i < areaProgress.Count; i++)
            if (areaProgress[i].areaId == areaId) return areaProgress[i];
        return null;
    }
}
